'use strict';
// refresh-apr1-2026.cjs
// Updates performance tracker JSON files with fresh week 2026-03-30 data.
// Replaces all 2026-03-30 rows then re-sorts and writes back.
// Also mirrors to dist/data/performance/ if that directory exists.

const fs = require('fs');
const path = require('path');

const BASE = 'C:/Users/kdwyer/Documents/claude/performance-tracker/public/data/performance';
const DIST = 'C:/Users/kdwyer/Documents/claude/performance-tracker/dist/data/performance';

// ── helpers ──────────────────────────────────────────────────────────────────
function readJson(file) {
  return JSON.parse(fs.readFileSync(path.join(BASE, file), 'utf8'));
}

function writeJson(file, data) {
  const str = JSON.stringify(data);
  fs.writeFileSync(path.join(BASE, file), str);
  if (fs.existsSync(DIST)) {
    fs.writeFileSync(path.join(DIST, file), str);
  }
}

function replace330(file, newRows) {
  const existing = readJson(file);
  const without330 = existing.filter(r => r.w !== '2026-03-30');
  const merged = [...without330, ...newRows];
  merged.sort((a, b) => {
    const wc = (a.w || '').localeCompare(b.w || '') || (a.c || '').localeCompare(b.c || '');
    if (wc !== 0) return wc;
    return (a.pr || '').localeCompare(b.pr || '');
  });
  writeJson(file, merged);
  const weeks = [...new Set(merged.map(r => r.w))].sort();
  console.log(`${file}: removed ${existing.length - without330.length}, added ${newRows.length} → total=${merged.length}, latest=${weeks[weeks.length - 1]}`);
}

// ── load locations whitelist ──────────────────────────────────────────────────
const locations = readJson('locations.json');
const knownCenters = new Set(locations.map(l => l.name));

function filterCenters(rows) {
  return rows.filter(r => knownCenters.has(r.c));
}

