const provHoursRows = filterCenters(schedLocData).map(r => {
  const h = Number(r.h) || 0;
  const bh = Number(r.bh) || 0;
  const sh = Math.max(0, h - bh);
  return { w: r.w, c: r.c, h, sh, bh };
});
