// weekly-utilization: ur = sh/h, cap at 1.0, only include if h > 0
const utilRows = filterCenters(schedLocData)
  .filter(r => (Number(r.h) || 0) > 0)
  .map(r => {
    const h = Number(r.h) || 0;
    const bh = Number(r.bh) || 0;
    const sh = Math.max(0, h - bh);
    const ur = Math.min(1.0, sh / h);
    return { w: r.w, c: r.c, ur: Math.round(ur * 1000) / 1000 };
  });
replace330('weekly-utilization.json', utilRows);

