// weekly-btx-provider: {w, c, pr, b, n}
const btxProvRows = filterCenters(btxProvData)
  .filter(r => r.pr && r.pr.trim())
  .map(r => ({
    w: r.w, c: r.c, pr: r.pr.trim(),
    b: Math.round(parseFloat(r.b) * 100) / 100,
    n: Number(r.n) || 0,
  }));
replace330('weekly-btx-provider.json', btxProvRows);

// weekly-btx: aggregate by w|c using weighted avg b = SUM(total_qty) / SUM(n)
const btxAgg = {};
for (const r of filterCenters(btxProvData)) {
  const key = r.w + '|' + r.c;
  if (!btxAgg[key]) btxAgg[key] = { w: r.w, c: r.c, totalQty: 0, totalN: 0 };
  btxAgg[key].totalQty += Number(r.total_qty) || 0;
  btxAgg[key].totalN += Number(r.n) || 0;
}
const btxRows = Object.values(btxAgg)
  .filter(r => r.totalN > 0)
  .map(r => ({
    w: r.w, c: r.c,
    b: Math.round((r.totalQty / r.totalN) * 100) / 100,
  }));
replace330('weekly-btx.json', btxRows);

