// weekly-util-hours-provider: {w, c, pr, h, sh, bh, ur}
// sh = max(0, h-bh); ur = sh/h capped at 1.0; only include if h > 0
const utilHoursProvRows = schedProvRaw
  .filter(r => r.w === '2026-03-30')
  .filter(r => knownCenters.has(r.c))
  .filter(r => r.pr && r.pr.trim())
  .filter(r => (Number(r.h) || 0) > 0)
  .map(r => {
    const h = Number(r.h) || 0;
    const bh = Number(r.bh) || 0;
    const sh = Math.max(0, h - bh);
    const ur = Math.min(1.0, sh / h);
    return {
      w: r.w, c: r.c, pr: r.pr.trim(),
      h, sh, bh,
      ur: Math.round(ur * 1000) / 1000,
    };
  });
replace330('weekly-util-hours-provider.json', utilHoursProvRows);

